    // Handle select (not X), Y, false -> false when X and Y are equivalent
    // sign-bit tests (e.g., X = trunc(lshr(V,31)), Y = icmp slt(V,0)).
    // When X is true, the condition is false and we return false.
    // When X is false, the condition is true and we return Y (= false).
    Value *NotArg;
    if (match(CondVal, m_Not(m_Value(NotArg)))) {
      // Check if TrueVal is equivalent to NotArg.
      // We handle the case where NotArg = trunc(lshr(V, BW-1)) and
      // TrueVal = icmp slt V, 0 (or similar sign-bit test).
      Value *V;
      const APInt *ShiftAmt;
      if (match(NotArg, m_Trunc(m_Lshr(m_Value(V), m_APIntAllowPoison(ShiftAmt))))) {
        unsigned VBitWidth = V->getType()->getScalarSizeInBits();
        if (ShiftAmt->uge(VBitWidth - 1) && ShiftAmt->ult(VBitWidth)) {
          // NotArg is extracting the sign bit via trunc(lshr(V, BW-1)).
